package com.wherefood.domain;
import jakarta.persistence.*; import java.time.*; import java.util.*;
@Entity @Table(name="items") public class Item { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) public Long id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="visit_id", nullable=false) public PlaceVisit visit; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="created_by", nullable=false) public User createdBy; @Column(nullable=false) public String name; public Instant deletedAt; public Instant createdAt; public Instant updatedAt; @OneToMany(mappedBy="item") public List<ItemReview> reviews = new ArrayList<>(); }
